// ── Auth ──────────────────────────────────────────────────────────────

export function useLogin(
  options?: UseMutationOptions<LoginResponse, Error, LoginBody>,
) {
  return useMutation({
    mutationFn: (body: LoginBody) =>
      customFetch<LoginResponse>({
        url: "/auth/login",
        method: "POST",
        data: body,
      }),
    ...options,
  });
}

export function useGetMe(
  options?: Partial<UseQueryOptions<User, Error>>,
) {
  return useQuery({
    queryKey: ["auth", "me"],
    queryFn: () =>
      customFetch<User>({ url: "/auth/me", method: "GET" }),
    ...options,
  });
}

